{"code": "import base64, json, requests, os

img_path = "/root/.hermes/image_cache/img_bc480d4ddb8c.jpg"
with open(img_path, "rb") as f:
    b64 = base64.b64encode(f.read()).decode()

# Use OpenRouter API directly with claude-sonnet-4 for vision
api_key = os.environ.get("OPENROUTER_API_KEY", "")
if not api_key:
    # Try .env
    with open("/root/.hermes/.env") as f:
        for line in f:
            if "OPENROUTER" in line and "KEY" in line:
                api_key = line.split("=",1)[1].strip().strip('"').strip("'")

print(f"API Key found: {bool(api_key)}")

if api_key:
    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json"
    }
    payload = {
        "model": "anthropic/claude-sonnet-4",
        "messages": [{
            "role": "user",
            "content": [
                {"type": "text", "text": "Read ALL the data from this egg production table. It's titled 'POSTURA' for Galpon 1, April 2026. The table has 30 rows (days 1-30). Columns: DIA, AVES (hens), then 3 intermediate columns, HUEVOS (total eggs), MAPLES A, MAPLES S, MAPLES J, MAPLES B, MAPLES C, MAPLES TOTAL, %POSTURA. Extract EVERY cell from every row. Output as JSON array."},
                {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{b64}"}}
            ]
        }],
        "max_tokens": 4000
    }
    resp = requests.post("https://openrouter.ai/api/v1/chat/completions", headers=headers, json=payload, timeout=120)
    print(f"Status: {resp.status_code}")
    print(resp.text[:5000])
else:
    print("No API key found")
